import { capitalize, isUndefined } from 'lodash-es';

import {
  _colorPaletteMap as colorPaletteMap,
  _isCustomColorPalette as isCustomColorPalette,
  ColorPalette,
} from '@dynatrace/strato-components/charts';

import { DEFAULT_BASIC_SHAPE_COLOR_TOKEN } from '../constants.js';

export const createCategoricalColorSchemeFromLegendProps = (
  colorPalette: string[] | ColorPalette,
  categories: string[],
): ColorPalette | { [key: string]: string } => {
  let obj = {};

  if (isCustomColorPalette(colorPalette)) {
    categories.forEach((categoryName, index) => {
      obj = {
        ...obj,
        [categoryName]:
          colorPalette[index] ?? DEFAULT_BASIC_SHAPE_COLOR_TOKEN.Default,
      };
    });
  } else {
    const colorsList = Object.values(colorPaletteMap[colorPalette]);
    categories.forEach((categoryName, i) => {
      const colorIndex = i % colorsList.length; // Using module in order to cycle through colorsList
      const colorToken =
        colorPaletteMap[colorPalette][capitalize(categoryName)] ??
        colorsList[colorIndex];
      if (!isUndefined(colorToken)) {
        obj = {
          ...obj,
          [categoryName]: colorToken.Default,
        };
      }
    });
  }
  return obj;
};
